#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_ACCOUNTS 1000
#define MAX_EMAILS 10
#define MAX_NAME_LENGTH 30
#define MAX_EMAIL_LENGTH 30

// Disjoint Set Union data structure
typedef struct {
    int* parent;
    int* rank;
} DisjointSet;

DisjointSet* createDS(int n) {
    DisjointSet* ds = (DisjointSet*)malloc(sizeof(DisjointSet));
    ds->parent = (int*)malloc(n * sizeof(int));
    ds->rank = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        ds->parent[i] = i;
        ds->rank[i] = 0;
    }
    return ds;
}

int findSet(DisjointSet* ds, int x) {
    if (ds->parent[x] != x)
        ds->parent[x] = findSet(ds, ds->parent[x]);
    return ds->parent[x];
}

void unionSet(DisjointSet* ds, int a, int b) {
    int pa = findSet(ds, a);
    int pb = findSet(ds, b);
    if (pa == pb) return;

    if (ds->rank[pa] < ds->rank[pb])
        ds->parent[pa] = pb;
    else if (ds->rank[pa] > ds->rank[pb])
        ds->parent[pb] = pa;
    else {
        ds->parent[pb] = pa;
        ds->rank[pa]++;
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        DisjointSet* ds = createDS(N);
        char** accounts = (char**)malloc(N * sizeof(char*));
        for (int i = 0; i < N; i++) {
            accounts[i] = (char*)malloc(MAX_ACCOUNTS * sizeof(char));
            scanf("%s", accounts[i]);
        }
        // Process accounts and emails
        for (int i = 0; i < N; i++) {
            int numEmails;
            scanf("%d", &numEmails);
            for (int j = 0; j < numEmails; j++) {
                char email[MAX_EMAIL_LENGTH];
                scanf("%s", email);
                // Check if email already exists in DSU
                for (int k = 0; k < i; k++) {
                    // If email exists, union current account with existing account
                    if (strcmp(email, accounts[k]) == 0) {
                        unionSet(ds, i, k);
                        break;
                    }
                }
            }
        }
        // Group emails by root parent and print merged accounts
        for (int i = 0; i < N; i++) {
            int root = findSet(ds, i);
            printf("%s ", accounts[root]);
            // Print sorted unique emails
            for (int j = 0; j < N; j++) {
                if (findSet(ds, j) == root) {
                    // Print emails associated with current account
                    int numEmails;
                    scanf("%d", &numEmails);
                    for (int k = 0; k < numEmails; k++) {
                        char email[MAX_EMAIL_LENGTH];
                        scanf("%s", email);
                        printf("%s ", email);
                    }
                }
            }
            printf("\n");
        }
        free(ds->parent);
        free(ds->rank);
        free(ds);
        for (int i = 0; i < N; i++) {
            free(accounts[i]);
        }
        free(accounts);
    }
    return 0;
}

