import java.util.Scanner;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Set;
import java.util.Map;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            String[] accounts = new String[N];
            for (int i = 0; i < N; i++)
                accounts[i] = scanner.next();
            // Process accounts and emails
            Map<String, Integer> emailToIndex = new HashMap<>();
            for (int i = 0; i < N; i++) {
                int numEmails = scanner.nextInt();
                for (int j = 0; j < numEmails; j++) {
                    String email = scanner.next();
                    // Check if email already exists in DSU
                    if (emailToIndex.containsKey(email)) {
                        // If email exists, union current account with existing account
                        int existingIndex = emailToIndex.get(email);
                        // Union
                        accounts[existingIndex] = mergeAccounts(accounts[existingIndex], accounts[i]);
                    } else {
                        emailToIndex.put(email, i);
                    }
                }
            }
            // Group emails by root parent and print merged accounts
            Set<String> uniqueAccounts = new HashSet<>();
            for (int i = 0; i < N; i++)
                uniqueAccounts.add(accounts[i]);
            for (String account : uniqueAccounts)
                System.out.println(account);
        }
    }
    public static String mergeAccounts(String account1, String account2) {
        // Merge two accounts into one
        return account1 + " " + account2;
    }
}

